// Extract the distinct lookup keys the parallel searches need:
//  - itemIds     : item_id of every table_gr line (to fetch Item masters)
//  - storageNames: distinct "Storage Location" names from the excel
//  - binCombines : distinct "Bin Location" combines from the excel
//  - uomNames    : distinct "UOM" names from the excel
const excelData = JSON.parse({{workflowparams:import_table_data}});
const tableGR = JSON.parse({{workflowparams:table_gr}});

const itemIds = [];
const storageNames = [];
const binCombines = [];
const uomNames = [];

(Array.isArray(tableGR) ? tableGR : []).forEach((r) => {
  const id = r && r.item_id ? String(r.item_id) : "";
  if (id && itemIds.indexOf(id) === -1) itemIds.push(id);
});

Object.keys(excelData).forEach((k) => {
  // numeric-keyed entries are data rows; skip name/size/type meta keys
  if (/^\d+$/.test(k)) {
    const row = excelData[k] || {};
    const s = row["Storage Location"] ? String(row["Storage Location"]).trim() : "";
    const b = row["Bin Location"] ? String(row["Bin Location"]).trim() : "";
    const u = row["UOM"] ? String(row["UOM"]).trim() : "";
    if (s && storageNames.indexOf(s) === -1) storageNames.push(s);
    if (b && binCombines.indexOf(b) === -1) binCombines.push(b);
    if (u && uomNames.indexOf(u) === -1) uomNames.push(u);
  }
});

// Never feed an empty array into an `in` filter; a "0" sentinel matches nothing.
if (itemIds.length === 0) itemIds.push("0");
if (storageNames.length === 0) storageNames.push("0");
if (binCombines.length === 0) binCombines.push("0");
if (uomNames.length === 0) uomNames.push("0");

return {
  itemIds: itemIds,
  storageNames: storageNames,
  binCombines: binCombines,
  uomNames: uomNames,
};

// Match imported excel rows to table_gr lines (by Item.material_code) and
// rebuild table_gr: fill a line in place (1 excel row) or replace it with
// Split-Parent rows (N excel rows). Duplicates/unknowns/serialized are skipped;
// hard validation problems accumulate into `errors` (any -> code 400).
const excelData = JSON.parse({{workflowparams:import_table_data}});
const tableGR = JSON.parse({{workflowparams:table_gr}});
const skipDuplicates = String({{workflowparams:skipDuplicates}} || "") === "true";

const itemList = {{node:search_node_item.data.data}} || [];
const storageList = {{node:search_node_storage.data.data}} || [];
const binList = {{node:search_node_bin.data.data}} || [];
const uomList = {{node:search_node_uom.data.data}} || [];
const binDefaultList = {{node:search_node_bin_default.data.data}} || [];

const str = (v) => (v === undefined || v === null ? "" : String(v));
const round3 = (n) => Math.round(n * 1000) / 1000;

// letter suffix A,B,...,Z,AA,... (ported from GRconfirmSplit.js)
const getLetterSuffix = (index) => {
  let suffix = "";
  let num = index;
  while (num >= 0) {
    suffix = String.fromCharCode(65 + (num % 26)) + suffix;
    num = Math.floor(num / 26) - 1;
  }
  return suffix;
};

// date parser (ported from GRsplitImportWorkflow): accepts DD-MM-YYYY, DD/MM/YYYY,
// YYYY-MM-DD, "1 Jan 2026"/"1 January 2026"/"1-Feb-2026"; year required; calendar-valid.
const MONTHS = {
  jan: 1, january: 1, feb: 2, february: 2, mar: 3, march: 3, apr: 4, april: 4,
  may: 5, jun: 6, june: 6, jul: 7, july: 7, aug: 8, august: 8,
  sep: 9, sept: 9, september: 9, oct: 10, october: 10, nov: 11, november: 11,
  dec: 12, december: 12,
};
const convertDate = (val) => {
  if (val === undefined || val === null || String(val).trim() === "") return null;
  const s = String(val).trim();
  let dNum, mNum, yNum, m;
  if ((m = s.match(/^(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})$/))) {
    yNum = parseInt(m[1], 10); mNum = parseInt(m[2], 10); dNum = parseInt(m[3], 10);
  } else if ((m = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/))) {
    dNum = parseInt(m[1], 10); mNum = parseInt(m[2], 10); yNum = parseInt(m[3], 10);
  } else if ((m = s.match(/^(\d{1,2})[\s\-]+([A-Za-z]+)[\s\-]+(\d{4})$/))) {
    dNum = parseInt(m[1], 10); yNum = parseInt(m[3], 10); mNum = MONTHS[m[2].toLowerCase()];
    if (!mNum) return { error: true, raw: s };
  } else {
    return { error: true, raw: s };
  }
  const isLeap = yNum % 4 === 0 && (yNum % 100 !== 0 || yNum % 400 === 0);
  const dim = [31, isLeap ? 29 : 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
  if (mNum < 1 || mNum > 12 || dNum < 1 || dNum > dim[mNum - 1]) return { error: true, raw: s };
  return yNum + "-" + String(mNum).padStart(2, "0") + "-" + String(dNum).padStart(2, "0");
};

// base_qty per 1 unit of uomId for an item (base UOM = 1 when it has no explicit row)
const baseQtyFor = (item, uomId) => {
  const conv = item && Array.isArray(item.table_uom_conversion) ? item.table_uom_conversion : [];
  const row = conv.find((c) => String(c.alt_uom_id) === String(uomId));
  if (row && row.base_qty) return parseFloat(row.base_qty);
  if (item && String(uomId) === String(item.based_uom)) return 1;
  return null;
};

// --- item lookup maps ---
const itemById = {};
const codeToItemId = {};
itemList.forEach((it) => {
  itemById[String(it.id)] = it;
  const code = str(it.material_code).trim();
  if (code) codeToItemId[code] = String(it.id);
});

// --- table_gr lines grouped by item_id; duplicates = item on 2+ lines ---
const rowsByItem = {};
(Array.isArray(tableGR) ? tableGR : []).forEach((line, idx) => {
  const id = str(line.item_id);
  if (!id) return;
  if (!rowsByItem[id]) rowsByItem[id] = [];
  rowsByItem[id].push(idx);
});
const duplicatedItemIds = {};
Object.keys(rowsByItem).forEach((id) => {
  if (rowsByItem[id].length > 1) duplicatedItemIds[id] = true;
});

// --- excel rows grouped by resolved item_id ---
const excelRows = [];
Object.keys(excelData).forEach((k) => {
  if (/^\d+$/.test(k)) excelRows.push({ __idx: parseInt(k, 10), data: excelData[k] || {} });
});
excelRows.sort((a, b) => a.__idx - b.__idx);

const excelByItemId = {};
const unknownCodes = [];
excelRows.forEach((r) => {
  const code = str(r.data["Item Code"]).trim();
  const itemId = codeToItemId[code];
  if (!itemId) {
    if (code && unknownCodes.indexOf(code) === -1) unknownCodes.push(code);
    return;
  }
  if (!excelByItemId[itemId]) excelByItemId[itemId] = [];
  excelByItemId[itemId].push(r.data);
});

// --- duplicate confirm gate ---
const dupHitCodes = [];
Object.keys(excelByItemId).forEach((itemId) => {
  if (duplicatedItemIds[itemId]) {
    const code = str((itemById[itemId] || {}).material_code).trim();
    if (code && dupHitCodes.indexOf(code) === -1) dupHitCodes.push(code);
  }
});
if (dupHitCodes.length > 0 && !skipDuplicates) {
  return {
    code: "409",
    message:
      "These item(s) appear on multiple GR lines and can't be matched from the file: " +
      dupHitCodes.join(", ") + ". Continue and skip them?",
    table_gr: "[]",
    warning: "",
    duplicates: dupHitCodes.join(", "),
  };
}

// --- build ---
const errors = [];
const unknownWarn = unknownCodes.slice();
const dupSkipped = [];
const serializedSkipped = [];
const autoBatchWarn = [];
const newTableGR = [];
let matchedCount = 0;

// validate one excel row for a matched item -> resolved sub-row (pushes to errors on problems)
const resolveRow = (row, item, code, lineUomFactor, seq) => {
  const label = 'Item "' + code + '" row ' + seq;
  // qty (+ optional UOM conversion to line UOM)
  const rawQty = parseFloat(row["Quantity"]);
  let qty = NaN;
  if (isNaN(rawQty) || rawQty <= 0) {
    errors.push(label + ": Quantity must be greater than 0.");
  } else {
    const uomName = str(row["UOM"]).trim();
    if (!uomName) {
      qty = rawQty;
    } else {
      // UOM names (PCS/UNIT/...) are not org-unique in the global UOM table, so
      // match the name AND require the id to be one of THIS item's UOMs
      // (baseQtyFor returns null for ids not in its conversion table/base UOM).
      const named = uomList.filter((u) => str(u.uom_name).trim() === uomName);
      let f = null;
      for (let n = 0; n < named.length; n++) {
        const bq = baseQtyFor(item, named[n].id);
        if (bq !== null) { f = bq; break; }
      }
      if (named.length === 0) {
        errors.push(label + ': UOM "' + uomName + '" not found.');
      } else if (f === null) {
        errors.push(label + ': UOM "' + uomName + '" is not valid for this item.');
      } else {
        qty = parseFloat((round3((rawQty * f) / lineUomFactor)).toFixed(3));
      }
    }
  }

  // Storage + bin resolution. Storage OR bin is enough:
  //  - storage given: resolve it; blank bin -> its default bin, else bin under it
  //  - only bin given: resolve the (unique) bin and derive its storage
  const storageName = str(row["Storage Location"]).trim();
  const binName = str(row["Bin Location"]).trim();
  let storageId = "";
  let locationId = "";
  if (!storageName && !binName) {
    errors.push(label + ": Storage Location or Bin Location is required.");
  } else if (storageName) {
    const storageMatches = storageList.filter(
      (s) => str(s.storage_location_name).trim() === storageName);
    if (storageMatches.length === 0) errors.push(label + ': Storage Location "' + storageName + '" not found.');
    else if (storageMatches.length > 1) errors.push(label + ': Storage Location "' + storageName + '" is ambiguous.');
    else storageId = storageMatches[0].id;

    if (!binName) {
      if (storageId) {
        const def = binDefaultList.find((b) => String(b.storage_location_id) === String(storageId));
        if (def) locationId = def.id;
        else errors.push(label + ': Bin Location is blank and Storage Location "' + storageName + '" has no default bin.');
      }
    } else if (storageId) {
      const binMatches = binList.filter(
        (b) => str(b.bin_location_combine).trim() === binName &&
          String(b.storage_location_id) === String(storageId));
      if (binMatches.length === 0) errors.push(label + ': Bin Location "' + binName + '" not found under Storage Location "' + storageName + '".');
      else if (binMatches.length > 1) errors.push(label + ': Bin Location "' + binName + '" is ambiguous under Storage Location "' + storageName + '".');
      else locationId = binMatches[0].id;
    }
  } else {
    // only bin given -> derive storage from the (unique) bin
    const binMatches = binList.filter((b) => str(b.bin_location_combine).trim() === binName);
    if (binMatches.length === 0) errors.push(label + ': Bin Location "' + binName + '" not found.');
    else if (binMatches.length > 1) errors.push(label + ': Bin Location "' + binName + '" exists under multiple storages; please specify Storage Location.');
    else { locationId = binMatches[0].id; storageId = String(binMatches[0].storage_location_id); }
  }

  // batch (mode from item; non-batch stored as "-" in table_gr)
  const isBatchItem = item ? item.item_batch_management === 1 : false;
  const isAutoBatch = isBatchItem && item.batch_number_genaration === "According To System Settings";
  let batchNo = "-";
  const excelBatch = str(row["Batch Number"]).trim();
  if (!isBatchItem) {
    batchNo = "-";
  } else if (isAutoBatch) {
    batchNo = "Auto-generated batch number";
    if (excelBatch !== "" && autoBatchWarn.indexOf(code) === -1) autoBatchWarn.push(code);
  } else {
    if (excelBatch === "") errors.push(label + ": Batch Number is required for this manual-batch item.");
    batchNo = excelBatch;
  }

  // dates (batch only)
  let mfg = null, exp = null;
  if (isBatchItem) {
    const m = convertDate(row["Manufacturing Date"]);
    const e = convertDate(row["Expired Date"]);
    if (m && m.error) errors.push(label + ': Manufacturing Date "' + m.raw + '" is not a valid date (use DD-MM-YYYY, DD/MM/YYYY or "1 Jan 2026").');
    else mfg = m;
    if (e && e.error) errors.push(label + ': Expired Date "' + e.raw + '" is not a valid date (use DD-MM-YYYY, DD/MM/YYYY or "1 Jan 2026").');
    else exp = e;
    if (typeof mfg === "string" && typeof exp === "string" && mfg > exp)
      errors.push(label + ": Manufacturing Date must be on or before Expired Date.");
  }

  return {
    qty: isNaN(qty) ? 0 : qty,
    storageId, locationId, batchNo, mfg, exp,
    r1: str(row["Remark"]), r2: str(row["Remark 2"]), r3: str(row["Remark 3"]),
  };
};

tableGR.forEach((line, idx) => {
  const itemId = str(line.item_id);
  const item = itemById[itemId];
  const rows = excelByItemId[itemId];
  const code = item ? str(item.material_code).trim() : str(line.item_name).trim();

  // no excel rows -> leave unchanged
  if (!rows || rows.length === 0) {
    newTableGR.push(line);
    return;
  }
  // duplicated item (only reached when skipping) -> leave unchanged
  if (duplicatedItemIds[itemId]) {
    if (code && dupSkipped.indexOf(code) === -1) dupSkipped.push(code);
    newTableGR.push(line);
    return;
  }
  // serialized -> skip (no serial column)
  if (item && item.serial_number_management === 1) {
    if (code && serializedSkipped.indexOf(code) === -1) serializedSkipped.push(code);
    newTableGR.push(line);
    return;
  }

  const orderedQty = parseFloat(line.ordered_qty) || 0;
  const initialReceivedQty = parseFloat(line.initial_received_qty) || 0;
  const uomConversion = parseFloat(line.uom_conversion) || 0;
  const unitPrice = parseFloat(line.unit_price) || 0;
  const lineUomFactor = baseQtyFor(item, str(line.item_uom)) || 1;

  // tolerance from item (by ordered UOM)
  let tol = 0;
  if (item && Array.isArray(item.table_uom_conversion)) {
    const c = item.table_uom_conversion.find((x) => String(x.alt_uom_id) === String(line.ordered_qty_uom));
    tol = (c && c.over_receive_tolerance) || 0;
  }

  const built = rows.map((row, i) => resolveRow(row, item, code, lineUomFactor, i + 1));
  const totalLineQty = round3(built.reduce((s, b) => s + b.qty, 0));

  // per-item tolerance (ordered-qty based, mirrors GRreceivedQty)
  const maxAllowed = round3((orderedQty * (100 + tol)) / 100);
  if (round3(totalLineQty + initialReceivedQty) > maxAllowed) {
    const maxQty = round3(maxAllowed - initialReceivedQty);
    errors.push('Item "' + code + '": total quantity (' + totalLineQty +
      ') exceeds maximum allowed (' + maxQty + ') based on tolerance.');
  }

  const baseOf = (qty) => (uomConversion > 0 ? round3(qty * uomConversion) : qty);
  const toRecv = (qty) => Math.max(0, round3(orderedQty - initialReceivedQty - qty));

  matchedCount++;

  if (built.length === 1) {
    // fill the line in place (stays Parent / is_split "No")
    const b = built[0];
    const row = Object.assign({}, line);
    delete row.fm_key;
    row.received_qty = b.qty;
    row.base_received_qty = baseOf(b.qty);
    row.to_received_qty = toRecv(b.qty);
    row.total_price = parseFloat((b.qty * unitPrice).toFixed(4));
    row.storage_location_id = b.storageId;
    row.location_id = b.locationId;
    row.item_batch_no = b.batchNo;
    row.manufacturing_date = b.mfg;
    row.expired_date = b.exp;
    row.line_remark_1 = b.r1;
    row.line_remark_2 = b.r2;
    row.line_remark_3 = b.r3;
    // imported rows must not inherit stale Handling Unit selections
    row.temp_hu_data = "[]";
    row.view_hu = "";
    newTableGR.push(row);
  } else {
    // replace with Split-Parent rows
    built.forEach((b, i) => {
      const row = Object.assign({}, line);
      delete row.fm_key;
      row.line_index = (parseInt(line.parent_index, 10) || 0) + 1 + "-" + getLetterSuffix(i);
      row.parent_or_child = "Split-Parent";
      row.is_split = "Yes";
      row.split_source_index = idx;
      row.parent_index = idx;
      row.received_qty = b.qty;
      row.base_received_qty = baseOf(b.qty);
      row.to_received_qty = toRecv(b.qty);
      row.total_price = parseFloat((b.qty * unitPrice).toFixed(4));
      row.storage_location_id = b.storageId;
      row.location_id = b.locationId;
      row.item_batch_no = b.batchNo;
      row.manufacturing_date = b.mfg;
      row.expired_date = b.exp;
      row.line_remark_1 = b.r1;
      row.line_remark_2 = b.r2;
      row.line_remark_3 = b.r3;
      row.temp_hu_data = "[]";
      row.view_hu = "";
      newTableGR.push(row);
    });
  }
});

if (errors.length > 0) {
  return { code: "400", message: errors.join("\n"), table_gr: "[]", warning: "", duplicates: "" };
}

const warnings = [];
if (matchedCount === 0) warnings.push("No items matched — nothing was imported.");
if (unknownWarn.length) warnings.push("Skipped item(s) not on this GR: " + unknownWarn.join(", ") + ".");
if (dupSkipped.length) warnings.push("Skipped item(s) on multiple GR lines: " + dupSkipped.join(", ") + ".");
if (serializedSkipped.length) warnings.push("Skipped serialized item(s) (add serials manually): " + serializedSkipped.join(", ") + ".");
if (autoBatchWarn.length) warnings.push('Ignored batch numbers for auto-generated item(s): ' + autoBatchWarn.join(", ") + ".");

return {
  code: "200",
  message: "",
  table_gr: JSON.stringify(newTableGR),
  warning: warnings.join("\n"),
  duplicates: "",
};
